# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from fastapi import FastAPI, HTTPException
from fastapi.responses import FileResponse
from pydantic import BaseModel
import os
from pathlib import Path
from typing import List, Optional

app = FastAPI()

ROOT_DIR = Path(os.environ.get("FILE_EXPLORER_ROOT", "./uploads")).resolve()


class PathRequest(BaseModel):
    path: Optional[str] = ""


def _safe_full_path(relative_path: str) -> str:
    relative_path = relative_path or ""
    normalized = os.path.normpath(relative_path)
    if normalized in (".", ""):
        normalized = ""
    full_path = os.path.join(str(ROOT_DIR), normalized)
    full_path = os.path.normpath(full_path)
    root_str = os.path.normpath(str(ROOT_DIR))
    if full_path != root_str and not full_path.startswith(root_str + os.sep):
        raise HTTPException(status_code=400, detail="Invalid path")
    return full_path


@app.get("/list")
def list_directory(path: str = ""):
    full_path = _safe_full_path(path)
    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail="Path not found")
    if not os.path.isdir(full_path):
        raise HTTPException(status_code=400, detail="Path is not a directory")

    items = []
    for name in os.listdir(full_path):
        item_path = os.path.join(full_path, name)
        items.append(
            {
                "name": name,
                "type": "directory" if os.path.isdir(item_path) else "file",
                "path": os.path.relpath(item_path, str(ROOT_DIR)),
            }
        )
    return {"path": path, "items": items}


@app.get("/download")
def download_file(path: str):
    full_path = _safe_full_path(path)
    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail="File not found")
    if not os.path.isfile(full_path):
        raise HTTPException(status_code=400, detail="Path is not a file")
    return FileResponse(full_path, filename=os.path.basename(full_path))


@app.get("/info")
def file_info(path: str):
    full_path = _safe_full_path(path)
    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail="Path not found")

    stat = os.stat(full_path)
    return {
        "path": path,
        "name": os.path.basename(full_path),
        "type": "directory" if os.path.isdir(full_path) else "file",
        "size": stat.st_size if os.path.isfile(full_path) else None,
        "modified_time": stat.st_mtime,
        "created_time": stat.st_ctime,
    }